def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("The list must have an even number of coefficients.")

    def derivative(xs):
        return [i * coeff for i, coeff in enumerate(xs)][1:]

    x0 = 0.0
    for _ in range(100):
        fx = poly(xs, x0)
        fpx = poly(derivative(xs), x0)
        if fpx == 0:
            break
        x0 -= fx / fpx
    return x0
```

