```python
    if len(xs) % 2 != 0:
        raise ValueError("Coefficient list must have an even number of coefficients.")

    def derivative(xs):
        return [i * coeff for i, coeff in enumerate(xs)][1:]

    def newton_raphson(x0):
        for _ in range(100):
            fx = poly(xs, x0)
            dfx = poly(derivative(xs), x0)
            if dfx == 0:
                break
            x1 = x0 - fx / dfx
            if abs(x1 - x0) < 1e-7:
                return x1
            x0 = x1
        return x0

    return newton_raphson(0)
```

```python
def find_zero(xs: list):
    if len(xs) % 2 != 0:
        raise ValueError("List must have an even number of coefficients.")
    a = xs[-1]
    b = xs[-2]
    return -b / (2 * a)
```
